/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);
    let sumOfK = 0;

    /**
     * Checks if an array can be sorted into its sorted version using cyclic shifts
     * on each subarray.
     * This is possible if and only if each subarray is a cyclic permutation of the corresponding segment
     * of the fully sorted array.
     * 
     * For a subarray nums[i*k ... (i+1)*k - 1], the elements must be a permutation
     * of sortedNums[i*k ... (i+1)*k - 1]. Since cyclic shifts preserve the set of elements,
     * we only need to check if the set of elements matches.
     * However, since we are checking if it *can* be sorted, the elements within the
     * subarray must exactly match the elements in the target sorted segment.
     * 
     * For a subarray of length k, any permutation can be reached if k > 1, 
     * *unless* the required permutation is not achievable by cyclic shifts.
     * 
     * A key property: A sequence can be sorted by cyclic shifts if and only if 
     * the elements within that sequence are exactly the elements that belong there 
     * in the final sorted array, AND the sequence is a cyclic shift of the target sequence.
     * 
     * Since we are allowed *arbitrary* cyclic shifts, if the elements in a subarray 
     * are a permutation of the elements in the target sorted segment, we can always sort it 
     * IF k >= 2.
     * If k=1, no shift is possible, so it must already be sorted (which it trivially is if it matches the target).
     * 
     * Let's re-read the operation: "independently on each subarray perform cyclic shift (left or right *any* number of times)".
     * This means for a subarray $S$, we can transform it into any cyclic shift of $S$.
     * 
     * If we partition $nums$ into $m = n/k$ blocks $B_1, B_2, \ldots, B_m$.
     * The target array is $S = sortedNums$.
     * The target blocks are $T_1, T_2, \ldots, T_m$, where $T_i = S[(i-1)k \ldots ik-1]$.
     * 
     * The transformation is possible if and only if for every block $i$, the current block $B_i$ 
     * can be transformed into $T_i$ by a cyclic shift.
     * This requires $B_i$ to be a cyclic shift of $T_i$.
     */
    const isCyclicPermutation = (arr1, arr2) => {
        if (arr1.length !== arr2.length) return false;
        if (arr1.length === 0) return true;

        const k = arr1.length;
        if (k === 1) return arr1[0] === arr2[0];

        // Check if arr2 is a cyclic shift of arr1.
        // Concatenate arr1 with itself: arr1 + arr1
        // arr2 must be a substring of this doubled array (when treated as sequences).

        // A simpler check: count element frequencies. Since T_i is sorted, 
        // if B_i has the same elements as T_i, and k>1, can we always cycle it to be sorted?
        // No. Example: T = [1, 2, 3]. B = [3, 1, 2]. Cyclic shifts: [3, 1, 2], [1, 2, 3], [2, 3, 1].
        // Since [1, 2, 3] is reachable, it works.
        // The property holds: if the multiset of elements in B_i equals the multiset in T_i, and k > 1, 
        // then B_i can be transformed into T_i if T_i is the only sorted state we care about, 
        // which is true because T_i is already sorted.

        // If the multiset of elements is the same, B_i is a permutation of T_i.
        // Since T_i is sorted, if B_i is not sorted, we need to check if the sorted state T_i is a cyclic shift of B_i.

        // Let's stick to the necessary and sufficient condition: B_i must be a cyclic shift of T_i.

        // 1. Check if multisets are equal (necessary condition)
        const counts1 = new Map();
        const counts2 = new Map();
        for (const x of arr1) counts1.set(x, (counts1.get(x) || 0) + 1);
        for (const x of arr2) counts2.set(x, (counts2.get(x) || 0) + 1);

        if (counts1.size !== counts2.size) return false;
        for (const [key, val] of counts1) {
            if (counts2.get(key) !== val) return false;
        }

        // 2. Check if arr2 is a cyclic shift of arr1.
        // Since arr2 (T_i) is sorted, we need to check if arr1 (B_i) is a cyclic shift of arr2 (T_i).
        // Wait, the operation is on B_i to make it look like T_i. So, B_i must be a cyclic shift of T_i.

        // Let S = arr2 (target, sorted). We check if arr1 is a cyclic shift of S.
        // We use the string matching trick if we map elements to characters, but since they are numbers, 
        // we simulate concatenation.

        // Double T_i (arr2)
        const doubledT = [...arr2, ...arr2];

        // Check if arr1 appears as a contiguous subsequence of length k in doubledT
        for (let start = 0; start < k; start++) {
            let match = true;
            for (let j = 0; j < k; j++) {
                if (arr1[j] !== doubledT[start + j]) {
                    match = false;
                    break;
                }
            }
            if (match) return true;
        }
        return false;
    };


    // Find all divisors of N
    const divisors = [];
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.push(i);
            if (i * i !== n) {
                divisors.push(n / i);
            }
        }
    }

    for (const k of divisors) {
        let isSortable = true;

        // Check every block
        const numBlocks = n / k;
        for (let i = 0; i < numBlocks; i++) {
            const start = i * k;

            // Current block B_i
            const currentBlock = nums.slice(start, start + k);

            // Target block T_i (from sortedNums)
            const targetBlock = sortedNums.slice(start, start + k);

            if (!isCyclicPermutation(currentBlock, targetBlock)) {
                isSortable = false;
                break;
            }
        }

        if (isSortable) {
            sumOfK += k;
        }
    }

    return sumOfK;
}

